18: package org.apache.kafka.server.util;
19: 
20: import org.apache.kafka.common.internals.FatalExitError;
21: import org.apache.kafka.common.utils.Exit;
22: import org.apache.kafka.common.utils.LogContext;
23: 
24: import org.slf4j.Logger;
25: 
26: import java.util.concurrent.CountDownLatch;
27: import java.util.concurrent.TimeUnit;
28: 
29: public abstract class ShutdownableThread extends Thread {
30: 
31:     public final String logPrefix;
32: 
33:     protected final Logger log;
34: 
35:     private final boolean isInterruptible;
36: 
37:     private final CountDownLatch shutdownInitiated = new CountDownLatch(1);
38:     private final CountDownLatch shutdownComplete = new CountDownLatch(1);
39: 
40:     private volatile boolean isStarted = false;
41: 
42:     public ShutdownableThread(String name) {
43:         this(name, true);
44:     }
45: 
46:     public ShutdownableThread(String name, boolean isInterruptible) {
47:         this(name, isInterruptible, "[" + name + "]: ");
48:     }
49: 
50:     @SuppressWarnings("this-escape")
51:     public ShutdownableThread(String name, boolean isInterruptible, String logPrefix) {
52:         super(name);
53:         this.isInterruptible = isInterruptible;
54:         this.logPrefix = logPrefix;
55:         log = new LogContext(logPrefix).logger(this.getClass());
56:         this.setDaemon(false);
57:     }
58: 
59:     public void shutdown() throws InterruptedException {
60:         initiateShutdown();
61:         awaitShutdown();
62:     }
63: 
64:     public boolean isShutdownInitiated() {
65:         return shutdownInitiated.getCount() == 0;
66:     }
67: 
68:     public boolean isShutdownComplete() {
69:         return shutdownComplete.getCount() == 0;
70:     }
71: 
72:     public boolean isStarted() {
73:         return isStarted;
74:     }
75: 
76:     /**
77:      * @return true if there has been an unexpected error and the thread shut down
78:      */
79:     // mind that run() might set both when we're shutting down the broker
80:     // but the return value of this function at that point wouldn't matter
81:     public boolean isThreadFailed() {
82:         return isShutdownComplete() && !isShutdownInitiated();
83:     }
84: 
85:     /**
86:      * @return true if the thread hasn't initiated shutdown already
87:      */
88:     public boolean initiateShutdown() {
89:         synchronized (this) {
90:             if (isRunning()) {
91:                 log.info("Shutting down");
92:                 shutdownInitiated.countDown();
93:                 if (isInterruptible)
94:                     interrupt();
95:                 return true;
96:             } else
97:                 return false;
98:         }
99:     }
100: 
101:     /**
102:      * After calling initiateShutdown(), use this API to wait until the shutdown is complete.
103:      */
104:     public void awaitShutdown() throws InterruptedException {
105:         if (!isShutdownInitiated())
106:             throw new IllegalStateException("initiateShutdown() was not called before awaitShutdown()");
107:         else {
108:             if (isStarted)
109:                 shutdownComplete.await();
110:             log.info("Shutdown completed");
111:         }
112:     }
113: 
114:     /**
115:      * Causes the current thread to wait until the shutdown is initiated,
116:      * or the specified waiting time elapses.
117:      *
118:      * @param timeout wait time in units.
119:      * @param unit    TimeUnit value for the wait time.
120:      */
121:     public void pause(long timeout, TimeUnit unit) throws InterruptedException {
122:         if (shutdownInitiated.await(timeout, unit))
123:             log.trace("shutdownInitiated latch count reached zero. Shutdown called.");
124:     }
125: 
126:     /**
127:      * This method is repeatedly invoked until the thread shuts down or this method throws an exception
128:      */
129:     public abstract void doWork();
130: 
131:     public void run() {
132:         isStarted = true;
133:         log.info("Starting");
134:         try {
135:             while (isRunning())
136:                 doWork();
137:         } catch (FatalExitError e) {
138:             shutdownInitiated.countDown();
139:             shutdownComplete.countDown();
140:             log.error("Stopped due to fatal error with exit code {}", e.statusCode(), e);
141:             Exit.exit(e.statusCode());
142:         } catch (Throwable e) {
143:             if (isRunning())
144:                 log.error("Error due to", e);
145:         } finally {
146:             shutdownComplete.countDown();
147:         }
148:         log.info("Stopped");
149:     }
150: 
151:     public boolean isRunning() {
152:         return !isShutdownInitiated();
153:     }
154: 
155: }
